  "title": "EXPLAIN ANALYZE गोटचा",
  "group": "प्रदर्शन",
  "options": [
    {
      "text": "हल्का योजना अनुमान"
    },
    {
      "text": "केवल SELECT पर काम करता है"
    },
    {
      "text": "डेटा बदलता है और योजना देता है"
    },
    {
      "text": "योजना पाने के लिए निष्पादन का अनुकरण करता है"
    }
  ],
  "questionProse": [
    "`EXPLAIN ANALYZE` `UPDATE` कथनों के लिए क्या करता है?"
  ],
  "explanationProse": [
    "`EXPLAIN ANALYZE` वास्तव में क्वेरी को चलाता है! लिखने वाले ऑपरेशन का विश्लेषण करते समय सावधान रहें, विशेष रूप से `UPDATE`, `DELETE`, और `INSERT` कथनों का। प्रत्येक `EXPLAIN ANALYZE` के बाद दोहराने योग्य परिणाम पाने के लिए आपको सफाई कार्य चलाने पड़ सकते हैं।\n\n    सर्वोत्तम प्रथाएँ:\n    - UPDATE/DELETE/INSERT के लिए `EXPLAIN` (बिना ANALYZE) उपयोग करें\n    - संशोधनों को लेन‑देन में घेरें:"
  ]
}
